        "12": { "class_type": "KSampler", "inputs": { "model": ["1", 0], "positive": ["10", 0], "negative": ["10", 1], "latent_image": ["11", 0], "seed": Math.floor(Math.random() * 2147483647), "steps": job.H3DSteps, "cfg": job.H3DCFG, "sampler_name": job.H3DSampler, "scheduler": job.H3DScheduler, "denoise": 1.0 }, "_meta": { "title": "KSampler (Hunyuan3D)" } },
