      comfyPrompt = {
        "1":  { "class_type": "unCLIPCheckpointLoader", "inputs": { "ckpt_name": job.Hunyuan3DCheckpoint }, "_meta": { "title": "Load Hunyuan3D v2.1" } },
        "2":  { "class_type": "LoadImage", "inputs": { "image": inputImg }, "_meta": { "title": "Load Front View" } },
        "6":  { "class_type": "CLIPVisionEncode", "inputs": { "clip_vision": ["1", 3], "image": ["2", 0], "crop": "center" }, "_meta": { "title": "Encode Front" } },
        "10": { "class_type": "Hunyuan3Dv2Conditioning", "inputs": { "clip_vision_output": ["6", 0] }, "_meta": { "title": "Single-View Conditioning" } },
