              throw new Error(errMsgs.length > 0 ? JSON.stringify(errMsgs[0]).substring(0, 400) : 'Execution error');
            }
            results.push({ ...job, Status: 'generated', GenerationMethod: genMethod, PromptId: promptId });
            generated = true;
            done = true;
          }
        } catch(e) {
          if (e.message.includes('Execution error') || e.message.includes('ComfyUI')) throw e;
          if (attempt % 24 === 0) console.warn('[Stage C] Poll ' + attempt + ' (' + genMethod + '): ' + e.message);
