// ============================================================
// Refine 3D Meshes
// ============================================================
// Post-processing on generated GLB files using Python trimesh:
//   1. Copy GLB from ComfyUI output to card directory
//   2. Clean degenerate faces, fill holes
//   3. Decimate to ~50k faces if over
//   4. Laplacian smoothing (5 iterations)
//   5. Fix normals
// Works with both Hunyuan3D and TripoSR outputs.
// ============================================================

const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const comfyOutputDir = 'D:/ComfyUI_windows_portable/ComfyUI/output';
const allItems = $input.all().map(item => item.json);
const results = [];

for (let idx = 0; idx < allItems.length; idx++) {
  const item = allItems[idx];

  if (item.Status !== 'generated') {
    results.push(item);
    continue;
  }

  const cardDir = item.CardDir;
  const glbFilename = item.GLBFilename;
  const glbDestPath = path.join(cardDir, glbFilename);

  // Find GLB in ComfyUI output (both Hunyuan3D SaveGLB and TripoSR SaveTripoSRMesh)
  const prefix = 'MODEL_' + item.CardSlug + '_' + item.Orientation;
  let glbSourcePath = null;

  try {
    const outputFiles = fs.readdirSync(comfyOutputDir);
    const matches = outputFiles.filter(f => f.startsWith(prefix) && f.endsWith('.glb')).sort().reverse();
    if (matches.length > 0) {
      glbSourcePath = path.join(comfyOutputDir, matches[0]);
    }
    // Hunyuan3D SaveGLB might use mesh/ subfolder
    if (!glbSourcePath) {
      const meshDir = path.join(comfyOutputDir, 'mesh');
      if (fs.existsSync(meshDir)) {
        const meshFiles = fs.readdirSync(meshDir);
        const meshMatches = meshFiles.filter(f => f.startsWith(prefix) && f.endsWith('.glb')).sort().reverse();
        if (meshMatches.length > 0) {
          glbSourcePath = path.join(meshDir, meshMatches[0]);
        }
      }
    }
  } catch(e) {
    results.push({ ...item, Status: 'failed', Reason: 'Cannot read output dir: ' + e.message });
    continue;
  }

  if (!glbSourcePath || !fs.existsSync(glbSourcePath)) {
    results.push({ ...item, Status: 'failed', Reason: 'GLB not found for prefix: ' + prefix });
    continue;
  }

  // Copy GLB to card directory
  try {
    fs.mkdirSync(cardDir, { recursive: true });
    fs.copyFileSync(glbSourcePath, glbDestPath);
  } catch(e) {
    results.push({ ...item, Status: 'failed', Reason: 'Copy GLB: ' + e.message });
    continue;
  }

  // Copy 3D reference image if it exists (from TripoSR path)
  const refPrefix = '3DREF_' + item.CardSlug + '_' + item.Orientation;
  try {
    const outputFiles = fs.readdirSync(comfyOutputDir);
    const refMatches = outputFiles.filter(f => f.startsWith(refPrefix) && f.endsWith('.png')).sort().reverse();
    if (refMatches.length > 0) {
      fs.copyFileSync(path.join(comfyOutputDir, refMatches[0]), path.join(cardDir, item.RefFilename));
    }
  } catch(e) { /* non-fatal */ }

  console.warn('[Refine] (' + (idx+1) + '/' + allItems.length + ') ' + item.CardName + ' ' + item.Orientation + ' (' + (item.GenerationMethod || 'unknown') + ')');

  // Refine mesh using Python trimesh
  const glbPathFwd = glbDestPath.replace(/\\/g, '/');
  const pyCode = [
    'import trimesh, sys, numpy as np',
    'm = trimesh.load(sys.argv[1])',
    'if hasattr(m, "geometry") and isinstance(m.geometry, dict):',
    '    m = trimesh.util.concatenate(list(m.geometry.values()))',
    'm.remove_degenerate_faces()',
    'm.remove_duplicate_faces()',
    'm.remove_unreferenced_vertices()',
    'm.fill_holes()',
    'target_faces = 50000',
    'if len(m.faces) > target_faces:',
    '    try:',
    '        m = m.simplify_quadric_decimation(target_faces)',
    '    except Exception:',
    '        pass',
    'try:',
    '    trimesh.smoothing.filter_laplacian(m, iterations=5)',
    'except Exception:',
    '    pass',
    'm.fix_normals()',
    'print(f"faces={len(m.faces)} verts={len(m.vertices)} watertight={m.is_watertight}")',
    'm.export(sys.argv[1])'
  ].join('\n');

  try {
    const output = execFileSync('python', ['-c', pyCode, glbPathFwd], { encoding: 'utf8', timeout: 120000 });
    const glbSize = fs.statSync(glbDestPath).size;
    results.push({ ...item, Status: 'refined', GLBPath: glbDestPath, GLBSizeKB: Math.round(glbSize / 1024), RefinementStats: output.trim() });
  } catch(e) {
    console.warn('[Refine] Failed: ' + e.message.substring(0, 200));
    const glbSize = fs.existsSync(glbDestPath) ? fs.statSync(glbDestPath).size : 0;
    results.push({ ...item, Status: 'generated', GLBPath: glbDestPath, GLBSizeKB: Math.round(glbSize / 1024), RefinementError: e.message.substring(0, 300) });
  }
}

const refined = results.filter(r => r.Status === 'refined').length;
const unrefined = results.filter(r => r.Status === 'generated').length;
console.warn('[Refine] Done: ' + refined + ' refined, ' + unrefined + ' unrefined');
return results.map(r => ({ json: r }));

// ============================================================
// Convert GLB to OBJ
// ============================================================

const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const allItems = $input.all().map(item => item.json);
const results = [];

for (const item of allItems) {
  if (item.Status !== 'refined' && item.Status !== 'generated') {
    results.push(item);
    continue;
  }

  const glbDestPath = item.GLBPath || path.join(item.CardDir, item.GLBFilename);
  const objDestPath = path.join(item.CardDir, item.OBJFilename);

  if (!fs.existsSync(glbDestPath)) {
    results.push({ ...item, Status: 'failed', Reason: 'GLB not found: ' + glbDestPath });
    continue;
  }

  try {
    const pyCode = 'import trimesh, sys; m = trimesh.load(sys.argv[1]); '
      + 'm = trimesh.util.concatenate(list(m.geometry.values())) if hasattr(m, "geometry") and isinstance(m.geometry, dict) else m; '
      + 'm.export(sys.argv[2])';
    execFileSync('python', ['-c', pyCode, glbDestPath.replace(/\\/g, '/'), objDestPath.replace(/\\/g, '/')], { encoding: 'utf8', timeout: 60000 });
    const glbSize = fs.statSync(glbDestPath).size;
    const objSize = fs.existsSync(objDestPath) ? fs.statSync(objDestPath).size : 0;
    results.push({ ...item, Status: 'completed', GLBPath: glbDestPath, OBJPath: objDestPath, GLBSizeKB: Math.round(glbSize / 1024), OBJSizeKB: Math.round(objSize / 1024) });
  } catch(e) {
    results.push({ ...item, Status: 'partial', GLBPath: glbDestPath, Reason: 'OBJ conversion failed: ' + e.message.substring(0, 300) });
  }
}

return results.map(r => ({ json: r }));

// ============================================================
// Report Results
// ============================================================

const allItems = $input.all().map(item => item.json);

const completed = allItems.filter(i => i.Status === 'completed');
const partial   = allItems.filter(i => i.Status === 'partial');
const failed    = allItems.filter(i => i.Status === 'failed');
const timeout   = allItems.filter(i => i.Status === 'timeout');

// Count by generation method
const byMethod = {};
for (const item of allItems) {
  const method = item.GenerationMethod || 'unknown';
  byMethod[method] = (byMethod[method] || 0) + 1;
}

const summary = {
  Total: allItems.length,
  Completed: completed.length,
  Partial: partial.length,
  Failed: failed.length,
  Timeout: timeout.length,
  ByMethod: byMethod,
  Details: allItems.map(i => ({
    Card: i.CardName,
    Orientation: i.Orientation,
    Status: i.Status,
    Method: i.GenerationMethod || '',
    GLBPath: i.GLBPath || '',
    OBJPath: i.OBJPath || '',
    GLBSizeKB: i.GLBSizeKB || 0,
    OBJSizeKB: i.OBJSizeKB || 0,
    Reason: i.Reason || ''
  }))
};

console.warn('=== 3D Object Generation Complete ===');
console.warn('Completed: ' + completed.length + '  Partial: ' + partial.length + '  Failed: ' + failed.length + '  Timeout: ' + timeout.length);
console.warn('By method: ' + JSON.stringify(byMethod));

if (failed.length > 0) {
  console.warn('Failed cards:');
  for (const f of failed) {
    console.warn('  - ' + f.CardName + ' ' + f.Orientation + ' (' + (f.GenerationMethod || '') + '): ' + (f.Reason || 'unknown'));
  }
}

return [{ json: summary }];
